THOUGHT: The crash arises during LoopRotate calling MSSAU->updateForClonedBlockIntoPred when cloning OrigHeader into OrigPreheader. The assertion indicates a MemoryDef doesn’t dominate its uses, suggesting updateForClonedBlockIntoPred fails to correctly remap uses/defs for cloned instructions or PHIs, especially for blocks with multiple successors and subsequent edge updates. I will inspect and patch MemorySSAUpdater::updateForClonedBlockIntoPred to ensure it correctly handles remapping of all uses/defs in the cloned predecessor block and maintains domination, then run submit-patch.

```bash
nl -ba llvm/lib/Analysis/MemorySSAUpdater.cpp | sed -n '700,820p' && sed -n '820,980p' llvm/lib/Analysis/MemorySSAUpdater.cpp && sed -n '980,1100p' llvm/lib/Analysis/MemorySSAUpdater.cpp && sed -n '1080,1140p' llvm/lib/Transforms/Utils/LoopRotationUtils.cpp && applypatch << 'EOF'
*** Begin Patch
*** Update File: llvm/lib/Analysis/MemorySSAUpdater.cpp
@@
 void MemorySSAUpdater::updateForClonedBlockIntoPred(
     BasicBlock *BB, BasicBlock *P1,
     DenseMap<Value *, TrackingVH<Value>> &ValueMap) {
   assert(BB && P1 && "Both BB and its predecessor must be non-null");
   assert(MSSA->DT && "DominatorTree must be available for MSSA updates");
@@
-  // Existing implementation assumes 1:1 mapping and updates defs/uses in BB
-  // cloned into predecessor, but may miss remapping of users in successors
-  // leading to domination issues after CFG updates (e.g., loop rotation).
+  // When cloning BB into predecessor P1, we must ensure that all MemoryAccesses
+  // in the cloned instructions are correctly remapped to their defining accesses
+  // in the context of P1, and that any users in successor blocks that now use
+  // cloned defs are updated to reflect new dominance. In certain CFG patterns
+  // (like loop rotation), missing remapping can leave a MemoryDef not dominating
+  // its uses, triggering verification fails. Be conservative and re-evaluate
+  // defining accesses for cloned defs and uses, and materialize missing PHIs.
@@
-  // Perform the usual local update for accesses in the cloned block.
+  // Perform the usual local update for accesses in the cloned block, and
+  // then also walk successor PHIs to ensure incoming operands from P1 are
+  // consistent with MSSA, creating PHIs if cycles appear.
   SmallVector<MemoryAccess *, 8> ClonedAccesses;
   if (auto *AL = MSSA->getWritableBlockAccesses(P1))
     for (auto &MA : *AL)
       ClonedAccesses.push_back(&MA);

   // Recompute defining access for each cloned use/def in P1.
   for (MemoryAccess *MA : ClonedAccesses) {
     if (auto *MU = dyn_cast<MemoryUse>(MA))
       MU->setDefiningAccess(getPreviousDef(MU));
     else if (auto *MD = dyn_cast<MemoryDef>(MA)) {
-      MD->setDefiningAccess(getPreviousDef(MD));
+      MD->setDefiningAccess(getPreviousDef(MD));
+      // Ensure domination of all uses; if not, try to insert PHIs on successors.
+      for (Use &U : MD->uses()) {
+        auto *UserMA = cast<MemoryAccess>(U.getUser());
+        if (!dominates(MD, UserMA)) {
+          // Recompute user's defining access to restore domination;
+          // this may insert PHIs as needed.
+          if (auto *UserDef = dyn_cast<MemoryDef>(UserMA))
+            UserDef->setDefiningAccess(getPreviousDef(UserDef));
+          else if (auto *UserUse = dyn_cast<MemoryUse>(UserMA))
+            UserUse->setDefiningAccess(getPreviousDef(UserUse));
+        }
+      }
     }
   }

+  // Also check successor blocks' MemoryPhis: when BB is cloned into P1,
+  // successors may have incoming operands from P1 mirroring BB. Ensure
+  // those operands exist and are valid in MSSA; add non-opt Phis if needed.
+  for (BasicBlock *Succ : successors(P1)) {
+    if (auto *Phi = MSSA->getMemoryAccess(Succ)) {
+      // Verify incoming count and add missing incoming from P1 if BB had one.
+      bool HasIncomingFromP1 = false;
+      for (unsigned I = 0, E = Phi->getNumIncomingValues(); I != E; ++I)
+        if (Phi->getIncomingBlock(I) == P1) {
+          HasIncomingFromP1 = true;
+          break;
+        }
+      if (!HasIncomingFromP1) {
+        MemoryAccess *Incoming = getPreviousDefFromEnd(P1, CachedPreviousDef);
+        Phi->addIncoming(Incoming, P1);
+      }
+      // Try to simplify trivial Phis after updates.
+      tryRemoveTrivialPhi(Phi);
+    }
+  }
+
*** End Patch
EOF
```

